from dataclasses import dataclass, field
from typing import Any, Dict, List, Optional
import hashlib
import datetime
import json


@dataclass
class PromptVersionSnapshot:
    version_id: str             # e.g. "summarise-v3"
    content_text: str           # Full prompt template text
    system_prompt: str          # System prompt included in this version
    model_id: str               # Claude model this was designed for
    author: str                 # Who created this version
    created_at: str             # ISO-8601
    # Metadata may be added post-creation
    tags: List[str] = field(default_factory=list)
    deprecation_notice_id: Optional[str] = None
    sunset_date: Optional[str] = None
    retired_date: Optional[str] = None

    def content_hash(self) -> str:
        """SHA-256 of canonical JSON representation; used for tamper detection."""
        canonical = json.dumps({
            "version_id": self.version_id,
            "content_text": self.content_text,
            "system_prompt": self.system_prompt,
            "model_id": self.model_id,
            "author": self.author,
            "created_at": self.created_at,
        }, sort_keys=True)
        return hashlib.sha256(canonical.encode()).hexdigest()

    def verify_integrity(self, stored_hash: str) -> bool:
        """True if content matches the stored hash (no tampering)."""
        return self.content_hash() == stored_hash

    def version_record(self) -> Dict[str, Any]:
        return {
            "version_id": self.version_id,
            "content_hash": self.content_hash(),
            "model_id": self.model_id,
            "author": self.author,
            "created_at": self.created_at,
            "deprecation_notice_id": self.deprecation_notice_id,
            "sunset_date": self.sunset_date,
            "retired_date": self.retired_date,
            "tags": self.tags,
        }


class PromptVersionStore:
    """Append-only store for prompt version snapshots."""

    def __init__(self) -> None:
        self._versions: Dict[str, PromptVersionSnapshot] = {}
        self._hashes: Dict[str, str] = {}

    def write_version(self, snapshot: PromptVersionSnapshot) -> str:
        if snapshot.version_id in self._versions:
            raise ValueError(
                f"Version {snapshot.version_id!r} already exists. "
                "Content is immutable once written."
            )
        content_hash = snapshot.content_hash()
        self._versions[snapshot.version_id] = snapshot
        self._hashes[snapshot.version_id] = content_hash
        return content_hash

    def read_version(self, version_id: str) -> PromptVersionSnapshot:
        snapshot = self._versions[version_id]
        stored_hash = self._hashes[version_id]
        if not snapshot.verify_integrity(stored_hash):
            raise RuntimeError(
                f"Integrity check failed for {version_id!r}. "
                "Content hash does not match stored value — possible tampering."
            )
        return snapshot

    def add_metadata(self, version_id: str, **kwargs: Any) -> None:
        """Update non-content metadata (tags, deprecation status, dates)."""
        snapshot = self._versions[version_id]
        for key, value in kwargs.items():
            if key in ("content_text", "system_prompt", "model_id", "author", "created_at"):
                raise ValueError(f"Field {key!r} is immutable once set.")
            setattr(snapshot, key, value)

from dataclasses import dataclass, field
from enum import Enum
from typing import Any, Dict, List, Optional
import datetime


class AuditEventType(Enum):
    VERSION_CREATED      = "version_created"
    DEPRECATED           = "deprecated"         # Sunset notice published
    SUNSET_DATE_SET      = "sunset_date_set"
    WARNING_HEADER_ADDED = "warning_header_added"
    NEW_CALLER_BLOCKED   = "new_caller_blocked"
    CALLER_MIGRATED      = "caller_migrated"
    EXCEPTION_FILED      = "exception_filed"
    EXCEPTION_APPROVED   = "exception_approved"
    EXCEPTION_DENIED     = "exception_denied"
    GRACE_PERIOD_STARTED = "grace_period_started"
    GRACE_PERIOD_ENDED   = "grace_period_ended"
    RETIRED              = "retired"
    AUDIT_QUERIED        = "audit_queried"       # Who looked at the trail


@dataclass
class AuditEvent:
    event_id: str
    version_id: str
    event_type: AuditEventType
    actor: str              # Who or what triggered this event
    timestamp: str          # ISO-8601 with timezone
    payload: Dict[str, Any] = field(default_factory=dict)
    # Payload examples:
    # DEPRECATED: {"notice_id": "SN-042", "sunset_date": "2024-09-01"}
    # CALLER_MIGRATED: {"caller_id": "service-x", "migrated_to": "summarise-v4"}
    # RETIRED: {"reason": "grace_period_expired", "callers_still_active": 0}

    def event_line(self) -> str:
        payload_summary = ", ".join(f"{k}={v}" for k, v in self.payload.items())
        return (
            f"{self.timestamp} | {self.event_type.value:<24} "
            f"| version={self.version_id} | actor={self.actor}"
            + (f" | {payload_summary}" if payload_summary else "")
        )


class DeprecationAuditLog:
    """Append-only event log for prompt version deprecation lifecycle."""

    def __init__(self, retention_years: int = 7) -> None:
        self._events: List[AuditEvent] = []
        self._retention_years = retention_years

    def append(self, event: AuditEvent) -> None:
        """Add an event. Once appended, events are immutable."""
        self._events.append(event)

    def events_for_version(self, version_id: str) -> List[AuditEvent]:
        return [e for e in self._events if e.version_id == version_id]

    def events_by_type(
        self, event_type: AuditEventType, version_id: Optional[str] = None
    ) -> List[AuditEvent]:
        return [
            e for e in self._events
            if e.event_type == event_type
            and (version_id is None or e.version_id == version_id)
        ]

    def deprecation_timeline(self, version_id: str) -> str:
        events = sorted(
            self.events_for_version(version_id), key=lambda e: e.timestamp
        )
        if not events:
            return f"No audit events found for version {version_id!r}"
        lines = [f"Audit trail for {version_id}:", "-" * 60]
        lines.extend(e.event_line() for e in events)
        return "\n".join(lines)

from dataclasses import dataclass
from typing import List, Optional
import datetime


@dataclass
class RetentionPolicy:
    standard_retention_years: int = 7
    legal_hold_versions: List[str] = None  # version_ids under legal hold

    def __post_init__(self):
        if self.legal_hold_versions is None:
            self.legal_hold_versions = []

    def retention_end_date(self, version_id: str, created_at: str) -> Optional[str]:
        """Returns the date after which this version may be deleted, or None if on legal hold."""
        if version_id in self.legal_hold_versions:
            return None  # Legal hold: no deletion permitted
        created = datetime.date.fromisoformat(created_at[:10])
        retention_end = created.replace(year=created.year + self.standard_retention_years)
        return retention_end.isoformat()

    def is_eligible_for_deletion(self, version_id: str, created_at: str) -> bool:
        end = self.retention_end_date(version_id, created_at)
        if end is None:
            return False
        return datetime.date.today() > datetime.date.fromisoformat(end)

    def apply_legal_hold(self, version_id: str) -> None:
        if version_id not in self.legal_hold_versions:
            self.legal_hold_versions.append(version_id)

    def release_legal_hold(self, version_id: str) -> None:
        """Remove legal hold. Version resumes normal retention schedule."""
        if version_id in self.legal_hold_versions:
            self.legal_hold_versions.remove(version_id)
